mapper.select:
SELECT COUNT(*)
FROM order_applications
WHERE order_id = #{orderId}
  AND provider_id = #{providerId}

mapper.delete:
DELETE
FROM order_applications
WHERE order_id = #{orderId}
  AND provider_id = #{providerId}

mapper.update:
UPDATE order_applications
SET apply_status = #{applyStatus}
WHERE order_id = #{orderId}
  AND provider_id = #{providerId}

UPDATE order_applications
SET apply_status = #{applyStatus}
WHERE order_id = #{orderId}
  AND provider_id != #{excludeProviderId}
